//! Benchmarking for pallet-emergency-pause.
//!
//! These are stubs — real weights should be generated by running:
//!   `cargo build --features runtime-benchmarks`
//!   `./target/release/clawchain-node benchmark pallet --pallet pallet_emergency_pause ...`

#![cfg(feature = "runtime-benchmarks")]

use super::*;
use crate::pallet::{
    CouncilMembers, NextProposalId, PalletId, PauseProposal, PauseVotes, ProposalKind,
};
use frame_benchmarking::v2::*;
use frame_support::traits::Get;
use frame_system::RawOrigin;
use sp_runtime::traits::Saturating;

fn add_council_member_helper<T: Config>(who: T::AccountId) {
    CouncilMembers::<T>::mutate(|members| {
        let _ = members.try_insert(who);
    });
}

fn make_pallet_id<T: Config>(seed: u8) -> PalletId<T> {
    let id_vec: Vec<u8> = alloc::format!("pallet-bench-{}", seed).into_bytes();
    BoundedVec::try_from(id_vec).expect("id fits within MaxPalletIdLen")
}

#[benchmarks]
mod benchmarks {
    use super::*;

    #[benchmark]
    fn propose_pause() {
        let caller: T::AccountId = whitelisted_caller();
        add_council_member_helper::<T>(caller.clone());

        #[extrinsic_call]
        propose_pause(RawOrigin::Signed(caller), b"pallet-bench-0".to_vec());
    }

    #[benchmark]
    fn propose_unpause() {
        let caller: T::AccountId = whitelisted_caller();
        add_council_member_helper::<T>(caller.clone());

        // First pause the pallet so we can unpause it.
        let pid = make_pallet_id::<T>(1);
        let now = frame_system::Pallet::<T>::block_number();
        let info = crate::pallet::PauseInfo {
            paused_at: now,
            expires_at: BlockNumberFor::<T>::from(0u32),
            reason: crate::pallet::PauseReason::CouncilVote,
            triggered_by: caller.clone(),
        };
        crate::pallet::PausedPallets::<T>::insert(pid, info);

        #[extrinsic_call]
        propose_unpause(RawOrigin::Signed(caller), b"pallet-bench-1".to_vec());
    }

    #[benchmark]
    fn vote() {
        let proposer: T::AccountId = whitelisted_caller();
        add_council_member_helper::<T>(proposer.clone());

        // Create a proposal manually.
        let pid = make_pallet_id::<T>(2);
        let now = frame_system::Pallet::<T>::block_number();
        let expires_at = now.saturating_add(T::ProposalExpiry::get());
        let proposal_id: ProposalId = 0;
        NextProposalId::<T>::put(1u64);
        let proposal = PauseProposal {
            pallet_id: pid,
            kind: ProposalKind::Pause,
            proposer: proposer.clone(),
            proposed_at: now,
            expires_at,
            votes: BoundedBTreeSet::new(),
        };
        PauseVotes::<T>::insert(proposal_id, proposal);
        crate::pallet::ActiveProposalCount::<T>::put(1u32);

        let voter: T::AccountId = account("voter", 0, 0);
        add_council_member_helper::<T>(voter.clone());

        #[extrinsic_call]
        vote(RawOrigin::Signed(voter), proposal_id);
    }

    #[benchmark]
    fn emergency_pause() {
        let caller: T::AccountId = whitelisted_caller();
        add_council_member_helper::<T>(caller.clone());

        #[extrinsic_call]
        emergency_pause(RawOrigin::Signed(caller));
    }

    #[benchmark]
    fn add_council_member() {
        let new_member: T::AccountId = account("new_member", 0, 0);

        #[extrinsic_call]
        add_council_member(RawOrigin::Root, new_member);
    }

    #[benchmark]
    fn remove_council_member() {
        let member: T::AccountId = account("member", 0, 0);
        // Need at least two members so we don't hit CannotRemoveLastMember.
        let anchor: T::AccountId = account("anchor", 1, 0);
        add_council_member_helper::<T>(member.clone());
        add_council_member_helper::<T>(anchor);

        #[extrinsic_call]
        remove_council_member(RawOrigin::Root, member);
    }

    #[benchmark]
    fn cancel_proposal() {
        let proposer: T::AccountId = whitelisted_caller();
        add_council_member_helper::<T>(proposer.clone());

        let pid = make_pallet_id::<T>(3);
        let now = frame_system::Pallet::<T>::block_number();
        let expires_at = now.saturating_add(T::ProposalExpiry::get());
        let proposal_id: ProposalId = 0;
        NextProposalId::<T>::put(1u64);
        let proposal = PauseProposal {
            pallet_id: pid,
            kind: ProposalKind::Pause,
            proposer: proposer.clone(),
            proposed_at: now,
            expires_at,
            votes: BoundedBTreeSet::new(),
        };
        PauseVotes::<T>::insert(proposal_id, proposal);
        crate::pallet::ActiveProposalCount::<T>::put(1u32);

        #[extrinsic_call]
        cancel_proposal(RawOrigin::Signed(proposer), proposal_id);
    }

    impl_benchmark_test_suite!(Pallet, crate::mock::new_test_ext(), crate::mock::Test);
}
